import json, time, urllib.request, urllib.parse

ids = ['bitcoin','ethereum','binancecoin','palm-ai','spectre-ai']
vs = 'eur'
url = 'https://api.coingecko.com/api/v3/simple/price?' + urllib.parse.urlencode({
    'ids': ','.join(ids),
    'vs_currencies': vs,
    'include_24hr_change': 'true'
})

attempt_delays = [0, 5, 15]
last_error = None
raw = None
for delay in attempt_delays:
    if delay:
        time.sleep(delay)
    try:
        req = urllib.request.Request(url, headers={'Accept': 'application/json', 'User-Agent': 'Mozilla/5.0'})
        with urllib.request.urlopen(req, timeout=30) as resp:
            raw = resp.read().decode('utf-8', errors='replace')
        data = json.loads(raw)
        if isinstance(data, dict) and 'status' in data and isinstance(data['status'], dict) and data['status'].get('error_code') == 429:
            last_error = 'CoinGecko rate limit: ' + raw
            continue
        break
    except Exception as e:
        last_error = str(e)
else:
    raise Exception('Impossible de récupérer CoinGecko après retries: ' + str(last_error))

if raw is None:
    raise Exception('Réponse CoinGecko vide.')

obj = json.loads(raw)
name_map = {
    'bitcoin': 'BTC',
    'ethereum': 'ETH',
    'binancecoin': 'BNB',
    'palm-ai': 'PALM AI',
    'spectre-ai': 'SPECTRE AI'
}
out = {}
for cid, symbol in name_map.items():
    item = obj.get(cid, {})
    out[symbol] = {
        'price_eur': item.get('eur'),
        'change_24h_pct': item.get('eur_24h_change')
    }

flow_file.content = json.dumps(out, ensure_ascii=False, indent=2).encode('utf-8')
